INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-1978', 'Pilar de la Horadada: appartements 2 chambres à moins de 2 km de la plage', '', '', 'Ce nouveau complexe résidentiel à Pilar de la Horadada vous propose des appartements 2 chambres à seulement quelques minutes des magnifiques plages de Torre de la Horadada et Mil Palmeras. Les appartements 2 chambres et 2 salles de bains situés au rez-de-chaussée disposent d''un jardin, ceux du 1er étage disposent d''un solarium. Place de parking privée. La résidence est entièrement clôturée et sécurisée, avec de beaux espaces verts et une piscine communautaire, parfaits pour se détendre toute l?année. Tous les services sont accessibles à pied : supermarchés, restaurants, écoles, commerces? Pilar de la Horadada, charmante ville au sud de la Costa Blanca, vous offre un cadre de vie agréable, en bord de mer et proche de toutes commodités. - Plages : 5 min - Golf Lo Romero : 10 min - Aéroport de Murcie : 40 min - Aéroport d?Alicante : 55 min - Centre commercial La Zenia Boulevard : 15 min - Port de plaisance Torre de la Horadada : 5 min Prix: à partir de 280.000 ? hors frais Livraison: entre 30/06 et 30/10/2027', '', '', 280000, 'pilar-de-la-horadada-appartements-2-chambres-a-moins-de-2-km-de-la-plage', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1980', 'Cox: belles maisons modernes en 2 chambres', '', '', 'Découvrez ce nouveau projet résidentiel exclusif à Cox , composé de 44 maisons au design moderne et fonctionnel. Disponibles en 2 ou 3 chambres, elles disposent toutes d?un solarium privé, de terrasses spacieuses, d?un patio et d?un parking privé. Chaque propriété est dotée d''un jardin paysager, d''un éclairage LED, de volets électriques, d''une pré-installation de panneaux solaires, d''armoires encastrées, d''une porte blindée, d''une cuisine entièrement équipée avec plans de travail Silestone et bien plus encore. La résidence comprend également de beaux espaces communs avec une belle piscine, créant un environnement idéal pour profiter du soleil de la Costa Blanca toute l?année. Située à seulement 40 km de l?aéroport international d?Alicante, cette promotion bénéficie d?une localisation stratégique : - Orihuela à 8 km - Elche à 20 km - Alicante à 48 km - Murcia à 25 km Pour les passionnés de golf, les parcours réputés La Finca (12 km) et Vistabella (14 km) sont facilement accessibles. Avec plus de 35 000 habitants, la zone offre un équilibre parfait entre vie paisible et dynamisme local. Les futurs résidents profiteront de toutes les commodités à proximité : - commerces, restaurants et services, - écoles et installations sportives, - centres médicaux, - et un accès rapide aux plages de la Costa Blanca comme Guardamar del Segura et Torrevieja. Prix: 219.000 ? hors frais Livraison: octobre ou décembre 2025', '', '', 219000, 'cox-belles-maisons-modernes-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1982', 'Santiago de la Ribera: villas modernes 3 chambres à 1 km de la mer', '', '', 'Situées dans le quartier recherché de San Blas, à Santiago de la Ribera, ces villas neuves allient design contemporain, confort et emplacement privilégié. Cette résidence comprend 12 villas mitoyennes, chacune avec piscine privée, à seulement 1 km des plages de la Mar Menor. Santiago de la Ribera, sur la Costa Cálida, est réputée pour son ambiance méditerranéenne, ses belles plages et son climat ensoleillé tout au long de l?année. Vous pourrez profiter d?un cadre de vie paisible tout en étant proche des commerces, restaurants et activités de loisirs. Chaque maison est répartie sur deux niveaux, offrant un espace lumineux et fonctionnel. Elles disposent de trois chambres, dont une au rez-de-chaussée, et de deux ou trois salles de bains. Les grandes baies vitrées ouvrent sur une terrasse et un jardin avec piscine privée, créant une continuité entre l?intérieur et l?extérieur. Certaines villas bénéficient également d?un solarium sur le toit, parfait pour se détendre, bronzer ou recevoir des invités. Ces villas ont été construites avec une attention particulière aux détails et selon des standards modernes. Elles sont livrées avec une cuisine entièrement équipée, comprenant les appareils électroménagers, et des salles de bains aménagées avec meubles, miroirs et éclairage. L''emplacement est idéal pour profiter pleinement de la région. La plage de la Mar Menor est accessible en quelques minutes à pied ou à vélo. Les centres commerciaux, les restaurants et les services essentiels se trouvent à proximité immédiate. Pour les amateurs de golf, le Roda Golf Resort est à seulement 5 km et Murcie et Carthagène sont facilement accessibles. Que vous recherchiez une résidence principale, une maison de vacances ou un investissement locatif, ces villas représentent une opportunité unique. Leur emplacement stratégique et leurs prestations haut de gamme garantissent un excellent potentiel locatif, tout en offrant un cadre de vie agréable toute l?année. Prix: à partir de 366.000 ? hors frais Fin des travaux: mai 2027', '', '', 366000, 'santiago-de-la-ribera-villas-modernes-3-chambres-a-1-km-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1984', 'Vistabella: superbes villas en 3 chambres', '', '', 'Découvrez ces villas de luxe situées au c?ur du complexe de golf de Vistabella, entre San Miguel de Salinas et Los Montesinos, sur la magnifique Costa Orihuela. Ces élégantes villas, construites sur deux niveaux, offrent un design moderne et des prestations haut de gamme : - 3 chambres spacieuses - 3 salles de bains - Grand séjour lumineux avec cuisine ouverte - Jardin privé avec piscine - Espace de stationnement sur la parcelle En option, vous pouvez ajouter un solarium privé, idéal pour profiter du soleil et des vues panoramiques. Les 18 trous du Vistabella Golf, par 72 et d''une longueur de plus de 6 000 mètres ont été conçus selon les directives des terrains modernes avec de larges fairways et des bunkers surélevés. À proximité immédiate, vous trouverez le club house, un restaurant, ainsi que divers bars et commerces locaux, accessibles en seulement 5 minutes à pied. Les charmantes villes de San Miguel de Salinas et Los Montesinos se situent à 5 minutes en voiture, tandis que les plages de Guardamar ne sont qu?à 15 minutes. Enfin, l?aéroport d?Alicante se trouve à 35 minutes, et celui de Corvera (Murcie) à 45 minutes. Prix: à partir de 385.000 ? hors frais Inclus: électroménagers, luminaires et parois de douche Livraison: entre septembre 2026 et mars 2027', '', '', 385000, 'vistabella-superbes-villas-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1985', 'Vistabella: belles maisons en 3 chambres', '', '', 'Découvrez un nouveau développement résidentiel haut de gamme situé dans le prestigieux Vistabella Golf Resort, entre San Miguel de Salinas et Los Montesinos, sur la Costa Blanca Sud. Les maisons disposent de 3 chambres et 3 salles de bains, de plusieurs terrasses et d''un solarium privé La résidence compte une piscine communautaire, une aire de jeux pour enfants et des jardins paysagers Le Vistabella Golf Resort offre un cadre de vie privilégié, entre nature, sport et détente. Son parcours 18 trous (par 72, plus de 6 000 m) séduit par ses fairways ondulés, bunkers stratégiques et lacs pittoresques, pour un plaisir de jeu unique à chaque trou. Le clubhouse, le restaurant, ainsi que les bars et commerces locaux se trouvent à seulement 5 minutes à pied. Les villes animées de San Miguel de Salinas et Los Montesinos sont accessibles en 5 minutes en voiture, tandis que les plages Pavillon Bleu de Guardamar se trouvent à 15 minutes. Prix: A partir de 299.000 ? hors frais Inclus dans le prix: électroménagers, luminaires et parois de douche', '', '', 299000, 'vistabella-belles-maisons-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2008', 'Mundo Aguilón: superbes appartements 2 chambres sur un golf', '', '', 'Ce nouveau complexe résidentiel exclusif se situe à Pulpí, dans un environnement privilégié entre mer et montagne, à deux pas du prestigieux Mundo Aguilón Golf. Le cadre est paisible, naturel et parfaitement intégré au paysage, offrant un art de vivre méditerranéen où se mêlent détente, activités de plein air et douceur du climat tout au long de l?année. À seulement quelques minutes en voiture se trouvent certaines des plages les plus préservées de la côte méditerranéenne. La résidence bénéficie ainsi d?un équilibre idéal entre proximité de la mer, vues dégagées sur le golf et tranquillité d?un quartier résidentiel bien établi, aussi agréable pour y vivre à l?année que pour profiter de séjours de vacances. Le projet comprend 54 appartements neufs de 1, 2 et 3 chambres, tous conçus avec une architecture contemporaine et des espaces intérieurs fonctionnels. Chaque logement dispose d?une place de parking privée et d?un débarras, tandis que les grandes terrasses permettent de profiter pleinement de la lumière naturelle et de vues panoramiques sur le parcours de golf et la mer. Une grande piscine commune invite à la détente lors des journées ensoleillées, un espace fitness permet de rester actif sans quitter la résidence, et un club-house ou espace social favorise les moments de convivialité entre voisins. La situation géographique est également un atout majeur. En plus de l?accès direct au golf, la résidence se trouve à proximité du port de Villaricos, à une courte distance des zones commerciales de Águilas, et non loin d?autres parcours renommés comme Desert Springs. Prix 2 chambres: à partir de 233.000 ? hors frais Inclus: - four, micro-ondes, taque vitrocéramique - climatisation Fin des travaux: mai 2028', '', '', 233000, 'mundo-aguilon-superbes-appartements-2-chambres-sur-un-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2009', 'Mundo Aguilón: superbes appartements 3 chambres sur un golf', '', '', 'Ce nouveau complexe résidentiel exclusif se situe à Pulpí, dans un environnement privilégié entre mer et montagne, à deux pas du prestigieux Mundo Aguilón Golf. Le cadre est paisible, naturel et parfaitement intégré au paysage, offrant un art de vivre méditerranéen où se mêlent détente, activités de plein air et douceur du climat tout au long de l?année. À seulement quelques minutes en voiture se trouvent certaines des plages les plus préservées de la côte méditerranéenne. La résidence bénéficie ainsi d?un équilibre idéal entre proximité de la mer, vues dégagées sur le golf et tranquillité d?un quartier résidentiel bien établi, aussi agréable pour y vivre à l?année que pour profiter de séjours de vacances. Le projet comprend 54 appartements neufs de 1, 2 et 3 chambres, tous conçus avec une architecture contemporaine et des espaces intérieurs fonctionnels. Chaque logement dispose d?une place de parking privée et d?un débarras, tandis que les grandes terrasses permettent de profiter pleinement de la lumière naturelle et de vues panoramiques sur le parcours de golf et la mer. Une grande piscine commune invite à la détente lors des journées ensoleillées, un espace fitness permet de rester actif sans quitter la résidence, et un club-house ou espace social favorise les moments de convivialité entre voisins. La situation géographique est également un atout majeur. En plus de l?accès direct au golf, la résidence se trouve à proximité du port de Villaricos, à une courte distance des zones commerciales de Águilas, et non loin d?autres parcours renommés comme Desert Springs. Prix 3 chambres: à partir de 263.000 ? hors frais Inclus: - four, micro-ondes, taque vitrocéramique - climatisation Fin des travaux: mai 2028', '', '', 263000, 'mundo-aguilon-superbes-appartements-3-chambres-sur-un-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1988', 'Hacienda del Alamo - Murcie: villas exclusives en 1ère ligne de golf', '', '', 'Découvrez une opportunité unique d?acquérir une villa de luxe en première ligne de golf au prestigieux Hacienda del Álamo Golf Resort, idéalement situé entre les villes historiques de Carthagène et Murcie, au c?ur de la Costa Cálida. Ces villas contemporaines allient confort, élégance et intimité dans un cadre exceptionnel dédié au golf et aux loisirs. Chaque villa offre un agencement généreux, adapté à votre style de vie : - 3 chambres, 2 salles de bains et toilettes invités - Terrains à partir de 700 m² et surface construite de 146 m² - Espaces pensés pour profiter pleinement de la vie intérieure et extérieure Ces villas en première ligne sont conçues pour un maximum de confort et de style : - Piscine privée et jardin paysager avec système d?irrigation automatique - Cuisine entièrement équipée avec armoires et électroménagers inclus - Climatisation centralisée dans toute la villa - Salles de bains avec meubles, miroirs et parois de douche Accès à une grande piscine communautaire, gazon naturel et aire de jeux pour enfants Le complexe de Hacienda del Alamo offre un mode de vie détendu, sportif et familial : - Parcours de golf de 18 trous et académie professionnelle - Installations sportives : tennis, paddle, salle de sport et cours de fitness - Club-house avec vue panoramique, restaurant méditerranéen et terrasses ensoleillées - Hôtel 4 étoiles et spa pour le bien-être et la détente - Espaces pour toute la famille : piscines, aires de jeux et pistes cyclables - Village espagnol traditionnel avec boutiques, cafés et nouveaux restaurants à venir Prix: à partir de 433.600 ? hors frais', '', '', 433600, 'hacienda-del-alamo-murcie-villas-exclusives-en-1ere-ligne-de-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1989', 'Hacienda del Alamo - Murcie: villas exclusives en 1ère ligne de golf', '', '', 'Découvrez une opportunité unique d?acquérir une villa de luxe en première ligne de golf au prestigieux Hacienda del Álamo Golf Resort, idéalement situé entre les villes historiques de Carthagène et Murcie, au c?ur de la Costa Cálida. Ces villas contemporaines allient confort, élégance et intimité dans un cadre exceptionnel dédié au golf et aux loisirs. Les villas, agencées sur 2 niveaux, offrent des espaces généreux: - 3 chambres, 2 salles de bains et toilettes invités - Terrains à partir de 700 m² et surface construite de 146 m² - Espaces pensés pour profiter pleinement de la vie intérieure et extérieure Ces villas en première ligne sont conçues pour un maximum de confort et de style : - Piscine privée et jardin paysager avec système d?irrigation automatique - Cuisine entièrement équipée avec armoires et électroménagers inclus - Climatisation centralisée dans toute la villa - Salles de bains avec meubles, miroirs et parois de douche Accès à une grande piscine communautaire, gazon naturel et aire de jeux pour enfants Le complexe de Hacienda del Alamo offre un mode de vie détendu, sportif et familial : - Parcours de golf de 18 trous et académie professionnelle - Installations sportives : tennis, paddle, salle de sport et cours de fitness - Club-house avec vue panoramique, restaurant méditerranéen et terrasses ensoleillées - Hôtel 4 étoiles et spa pour le bien-être et la détente - Espaces pour toute la famille : piscines, aires de jeux et pistes cyclables - Village espagnol traditionnel avec boutiques, cafés et nouveaux restaurants à venir Prix: à partir de 432.200 ? hors frais', '', '', 432200, 'hacienda-del-alamo-murcie-villas-exclusives-en-1ere-ligne-de-golf-2', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1990', 'Hacienda del Alamo - Murcie: villas exclusives en 1ère ligne de golf', '', '', 'Découvrez une opportunité unique d?acquérir une villa de luxe en première ligne de golf au prestigieux Hacienda del Álamo Golf Resort, idéalement situé entre les villes historiques de Carthagène et Murcie, au c?ur de la Costa Cálida. Ces villas contemporaines allient confort, élégance et intimité dans un cadre exceptionnel dédié au golf et aux loisirs. Chaque villa offre un agencement généreux, adapté à votre style de vie : - 3 chambres, 2 salles de bains et toilettes invités - Terrains à partir de 880 m² et surface construite de 146 m² - Espaces pensés pour profiter pleinement de la vie intérieure et extérieure Ces villas en première ligne sont conçues pour un maximum de confort et de style : - Piscine privée et jardin paysager avec système d?irrigation automatique - Cuisine entièrement équipée avec armoires et électroménagers inclus - Climatisation centralisée dans toute la villa - Salles de bains avec meubles, miroirs et parois de douche Accès à une grande piscine communautaire, gazon naturel et aire de jeux pour enfants Le complexe de Hacienda del Alamo offre un mode de vie détendu, sportif et familial : - Parcours de golf de 18 trous et académie professionnelle - Installations sportives : tennis, paddle, salle de sport et cours de fitness - Club-house avec vue panoramique, restaurant méditerranéen et terrasses ensoleillées - Hôtel 4 étoiles et spa pour le bien-être et la détente - Espaces pour toute la famille : piscines, aires de jeux et pistes cyclables - Village espagnol traditionnel avec boutiques, cafés et nouveaux restaurants à venir Prix: à partir de 463.600 ? hors frais', '', '', 463600, 'hacienda-del-alamo-murcie-villas-exclusives-en-1ere-ligne-de-golf-3', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1991', 'Hacienda del Alamo - Murcie: superbes villas en 3 chambres', '', '', 'Ces superbes villas sont situées dans le prestigieux Hacienda del Álamo Golf Resort, un complexe résidentiel sécurisé au c?ur de la région de Murcie. Un lieu idéal pour profiter d?un cadre naturel exceptionnel, d?un climat méditerranéen ensoleillé et d?un style de vie paisible et raffiné, à proximité de toutes les commodités. Les villas, de plain-pied et construites sur des parcelles à partir de 550 m², offrent : - 3 chambres et 2 salles de bains complètes sur un seul niveau - Un vaste salon lumineux ouvert sur la terrasse et la piscine privée - Un solarium panoramique sur le toit avec vue sur le golf - Un jardin paysager et un parking privé Hacienda del Álamo Golf Resort est l?un des complexes résidentiels les plus complets de la Costa Cálida. Vous y trouverez : - Un terrain de golf 18 trous - Un hôtel avec spa - Des restaurants et bars - Un supermarché - Des installations sportives et de vastes espaces verts - Sécurité 24h/24 L?urbanisation recrée l?ambiance d?un village méditerranéen traditionnel, avec ses rues calmes et son architecture harmonieuse. Un emplacement idéal pour vivre toute l?année ou profiter de séjours ensoleillés dans un cadre exclusif. Prix: à partir de 354.900 ? hors frais Livraison: 1 an à partir de la signature du contrat', '', '', 354900, 'hacienda-del-alamo-murcie-superbes-villas-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1992', 'Hacienda del Alamo - Murcie: magnifiques villas en 3 chambres', '', '', 'Ces superbes villas sont situées dans le prestigieux Hacienda del Álamo Golf Resort, un complexe résidentiel sécurisé au c?ur de la région de Murcie. Un lieu idéal pour profiter d?un cadre naturel exceptionnel, d?un climat méditerranéen ensoleillé et d?un style de vie paisible et raffiné, à proximité de toutes les commodités. Le lotissement se compose de 39 villas sur des parcelles à partir de 436 m². Toutes les villas disposent de 3 chambres et 2 salles de bains complètes sur un seul étage, ainsi que d''une terrasse avec piscine privée et d''un solarium privé sur le toit avec vue sur le terrain de golf. Hacienda del Álamo Golf Resort est l?un des complexes résidentiels les plus complets de la Costa Cálida. Vous y trouverez : - Un terrain de golf 18 trous - Un hôtel avec spa - Des restaurants et bars - Un supermarché - Des installations sportives et de vastes espaces verts - Sécurité 24h/24 L?urbanisation recrée l?ambiance d?un village méditerranéen traditionnel, avec ses rues calmes et son architecture harmonieuse. Un emplacement idéal pour vivre toute l?année ou profiter de séjours ensoleillés dans un cadre exclusif. Prix: à partir de 374.900 ? hors frais Livraison: 1 an à partir de la signature du contrat', '', '', 374900, 'hacienda-del-alamo-murcie-magnifiques-villas-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1993', 'Fuente Alamo : appartements modernes en 2 chambres', '', '', 'Cette résidence est située à Fuente Alamo, dans la région paisible de Murcie. Vous trouverez des appartements au rez-de-chaussée avec jardin privé et des appartements à l?étage avec solarium privé, offrant un cadre idéal pour profiter de la vie en plein air et de la beauté de la campagne murcienne. Situé loin de l?agitation des grandes villes et de la pression touristique de la côte, cet emplacement vous invite à vivre dans un environnement serein et durable. Chaque matin, réveillez-vous au c?ur de paysages naturels, entouré par la tranquillité et la beauté unique de la région. Ce projet intègre les dernières normes en matière de performance énergétique, avec des matériaux respectueux de l?environnement et une conception harmonieuse avec le milieu rural. Fuente Álamo de Murcia est une commune du sud de l?Espagne, à 22 km au nord-ouest de Carthagène et 35 km au sud-ouest de Murcie. Nichée entre les sierras d?Algarrobo, Los Gómez, Los Victorias et Carrascoy, elle bénéficie d?un environnement naturel exceptionnel avec des cours d?eau menant à la Mar Menor. Prix: à partir de 169.119 ? hors frais Inclus: électroménagers', '', '', 169119, 'fuente-alamo-appartements-modernes-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2007', 'Mundo Aguilón: superbes appartements 1 chambre sur un golf', '', '', 'Ce nouveau complexe résidentiel exclusif se situe à Pulpí, dans un environnement privilégié entre mer et montagne, à deux pas du prestigieux Mundo Aguilón Golf. Le cadre est paisible, naturel et parfaitement intégré au paysage, offrant un art de vivre méditerranéen où se mêlent détente, activités de plein air et douceur du climat tout au long de l?année. À seulement quelques minutes en voiture se trouvent certaines des plages les plus préservées de la côte méditerranéenne. La résidence bénéficie ainsi d?un équilibre idéal entre proximité de la mer, vues dégagées sur le golf et tranquillité d?un quartier résidentiel bien établi, aussi agréable pour y vivre à l?année que pour profiter de séjours de vacances. Le projet comprend 54 appartements neufs de 1, 2 et 3 chambres, tous conçus avec une architecture contemporaine et des espaces intérieurs fonctionnels. Chaque logement dispose d?une place de parking privée et d?un débarras, tandis que les grandes terrasses permettent de profiter pleinement de la lumière naturelle et de vues panoramiques sur le parcours de golf et la mer. Une grande piscine commune invite à la détente lors des journées ensoleillées, un espace fitness permet de rester actif sans quitter la résidence, et un club-house ou espace social favorise les moments de convivialité entre voisins. La situation géographique est également un atout majeur. En plus de l?accès direct au golf, la résidence se trouve à proximité du port de Villaricos, à une courte distance des zones commerciales de Águilas, et non loin d?autres parcours renommés comme Desert Springs. Prix 1 chambre: à partir de 177.000 ? hors frais Inclus: - four, micro-ondes, taque vitrocéramique - climatisation Fin des travaux: mai 2028', '', '', 177000, 'mundo-aguilon-superbes-appartements-1-chambre-sur-un-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1994', 'Vistabella: superbes villas en 3 chambres', '', '', 'Offrez-vous un style de vie exclusif dans l?un des complexes résidentiels les plus prisés de la région. Ces villas neuves, idéalement situées au Vistabella Golf Resort, allient design contemporain, prestations haut de gamme et un environnement golfique exceptionnel. Les villas 3 chambres sont de plain-pied. Chaque villa est située sur un terrain d?environ 300 m² et dispose d''une piscine privée, d''une place de parking sur la parcelle, d''un vaste solarium, de beaux espaces extérieurs ainsi que finitions luxueuses: - Climatisation réversible - Cuisine équipée complète - Volets électriques - Éclairage extérieur - Parois de douche design - Matériaux modernes et soigneusement sélectionnés Élégance, confort et durabilité se rencontrent pour offrir un lieu idéal à vivre ou à louer. Vistabella Golf Resort est une communauté fermée avec un parcours de golf 18 trous, des courts de paddle-tennis, un supermarché et un large choix de bars et de restaurants. De futurs aménagements feront de ce complexe une véritable destination 5 étoiles, avec notamment un bar à champagne, un bar à sushis, un hôtel spa, une plage artificielle, un court de tennis, un terrain de football et un bar gastronomique. Profitez d?un accès facile aux sites incontournables de la Costa Blanca : - Plage de La Mata : 18 km - Guardamar del Segura : 20 km - Torrevieja : 15 km - Aéroport d?Alicante : 55 km - Aéroport de Murcie : 68 km - Villamartín Golf : 12 km - Las Colinas Golf & Country Club : 14 km Prix: àpd de 469.900 ? hors frais', '', '', 469900, 'vistabella-superbes-villas-en-3-chambres-2', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1995', 'Vistabella: superbes villas en 4 chambres', '', '', 'Offrez-vous un style de vie exclusif dans l?un des complexes résidentiels les plus prisés de la région. Ces villas neuves, idéalement situées au Vistabella Golf Resort, allient design contemporain, prestations haut de gamme et un environnement golfique exceptionnel. Les villas 4 chambres sont agencées sur 2 niveaux. Chaque villa est située sur un terrain d?environ 300 m² et dispose d''une piscine privée, d''une place de parking sur la parcelle, de beaux espaces extérieurs ainsi que finitions luxueuses: - Climatisation réversible - Cuisine équipée complète - Volets électriques - Éclairage extérieur - Parois de douche design - Matériaux modernes et soigneusement sélectionnés Élégance, confort et durabilité se rencontrent pour offrir un lieu idéal à vivre ou à louer. Vistabella Golf Resort est une communauté fermée avec un parcours de golf 18 trous, des courts de paddle-tennis, un supermarché et un large choix de bars et de restaurants. De futurs aménagements feront de ce complexe une véritable destination 5 étoiles, avec notamment un bar à champagne, un bar à sushis, un hôtel spa, une plage artificielle, un court de tennis, un terrain de football et un bar gastronomique. Profitez d?un accès facile aux sites incontournables de la Costa Blanca : - Plage de La Mata : 18 km - Guardamar del Segura : 20 km - Torrevieja : 15 km - Aéroport d?Alicante : 55 km - Aéroport de Murcie : 68 km - Villamartín Golf : 12 km - Las Colinas Golf & Country Club : 14 km Prix: àpd de 549.900 ? hors frais', '', '', 549900, 'vistabella-superbes-villas-en-4-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1998', 'Finestrat: magnifiques villas en 3 chambres avec vue sur mer', '', '', 'Découvrez ces villas nichées au c?ur du prestigieux quartier de Sierra Cortina, à Finestrat. Situées dans un environnement naturel d?exception tout en restant proches de Benidorm, ces propriétés haut de gamme séduisent par leur design moderne, leurs prestations d?excellence et leur emplacement privilégié à quelques minutes de la côte méditerranéenne. À seulement 5 km du centre animé de Benidorm, elles offrent un équilibre parfait entre tranquillité, confort et proximité des services. Chaque villa propose 3 chambres et 3 élégantes salles de bains, offrant de généreux volumes pour accueillir famille et invités. Le c?ur de la maison est un vaste séjour ouvert, combinant salon, salle à manger et cuisine intégrée dans un espace lumineux et convivial. Certaines villas disposent également d?un sous-sol modulable, parfait pour créer une salle de sport, un home-cinéma ou tout autre espace de loisirs sur mesure. Les villas intègrent les dernières innovations en matière de domotique : gestion intelligente de l?éclairage, des stores et de la climatisation, systèmes de sécurité avancés (interphone vidéo, contrôle à distance). L?ensemble garantit une habitation moderne, sûre et éco-efficiente. Chaque villa bénéficie d?un jardin privatif soigneusement aménagé, véritable havre de paix pour profiter du climat méditerranéen. Une piscine privée complète cet espace. Le jardin, doté d?un arrosage automatique et d?un éclairage subtil, crée une atmosphère apaisante et élégante à toute heure. Parfaitement situées, les villas offrent un accès rapide aux principales attractions de la région : * Les plages de Benidorm à seulement 4 km * L?aéroport d?Alicante-Elche à environ 50 km * Le prestigieux **Villaitana Golf** à 3 km * Le centre commercial **La Marina** à 2 km, regroupant boutiques, restaurants et loisirs Un cadre de vie exclusif, entre nature, luxe et confort, au sein d?un des quartiers les plus recherchés de la Costa Blanca. Prix: à partir de 895.000 ? hors frais', '', '', 895000, 'finestrat-magnifiques-villas-en-3-chambres-avec-vue-sur-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1999', 'Cuuevas de Almanzora: villas jumelée 4 chambres en bord de mer', '', '', 'Une vie exclusive face à la Méditerranée ! Découvrez un ensemble unique de 6 villas jumelées de prestige, idéalement situées en première ligne de mer à Cala Panizo, dans la commune de Cuevas de Almanzora. Pensées pour ceux qui recherchent tranquillité, raffinement et contact direct avec la mer, ces propriétés offrent un cadre de vie d?exception où le murmure des vagues et la vue panoramique deviennent votre quotidien. Les villas disposent de 4 chambres et 3 salles de bains, alliant design méditerranéen moderne, fonctionnalité et matériaux de premier choix. Les intérieurs se distinguent par leurs volumes généreux, leurs espaces lumineux et leurs finitions soignées. Au rez-de-chaussée, vous trouverez : - un garage fermé, - un espace buanderie, - un vaste séjour avec cuisine ouverte, - une chambre et une salle de bains, - un accès direct à un porche couvert, - un jardin paysager offrant une piscine à débordement avec vue imprenable sur la mer. À l?étage: trois chambres supplémentaires et deux salles de bains, dont une suite parentale. Le solarium de 69 m² vient sublimer la villa : espace pour cuisine d?été, pré-installation pour jacuzzi, vues magnifiques? l?endroit rêvé pour savourer les couchers de soleil en toute sérénité. Pour un confort optimal, les villas sont également pré-équipées pour l?installation d?un ascenseur. Elles bénéficient de cuisines entièrement aménagées avec électroménagers, de salles de bains complètes, d?une climatisation centralisée haute performance et de matériaux raffinés. Un emplacement exceptionnel face à la mer : Cala Panizo est une enclave résidentielle paisible reconnue pour ses criques préservées, ses eaux cristallines et son environnement naturel unique. Le projet se situe au sud de Pozo del Esparto et à proximité de Mar de Pulpí, San Juan de los Terreros et du parcours d?Aguilón Golf. La charmante ville d?Águilas, avec sa marina, ses services et ses restaurants, est également facilement accessible. Prix: à partir de 1.070.000 ? hors frais Livraison: décembre 2026', '', '', 1070000, 'cuuevas-de-almanzora-villas-jumelee-4-chambres-en-bord-de-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2000', 'Campoamor: luxueuse villa 3 chambres à proximité de la mer', '', '', 'Cette villa est située dans un environnement offrant de magnifiques vues sur la mer ainsi que sur les pinèdes de Campoamor, cette villa vous invite à savourer une vie sereine et détendue. Pensée pour maximiser le confort, la villa dispose d?un spacieux séjour-salle à manger, d''une cuisine ouverte moderne et fonctionnelle, de 3 chambres, dont une suite parentale dotée d?un dressing, d?une salle de bains privative et d?une superbe vue sur la pinède et l?horizon marin. Une vie entre mer et golf au c?ur d?Orihuela Costa Avec sa terrasse, son jardin privé et sa piscine, cette villa moderne offre tout ce dont vous avez besoin pour améliorer votre qualité de vie au bord de la Méditerranée. Ses extérieurs généreux et soigneusement conçus permettent de savourer pleinement le soleil, la tranquillité et l?intimité qu?offre la Costa Blanca. La région séduit également les passionnés de golf : à proximité immédiate de la villa se trouvent des parcours d?exception tels que Las Colinas Golf & Country Club, Las Ramblas, Villamartín Golf ou encore le Real Club de Golf Campoamor Resort. Prix: 1.175.000 ? hors frais', '', '', 1175000, 'campoamor-luxueuse-villa-3-chambres-a-proximite-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2003', 'Torrevieja: superbes appartements modernes en 2 chambres', 'Torrevieja: prachtige moderne appartementen met 2 slaapkamers', '', 'Découvrez ce nouveau complexe résidentiel d?appartements neufs à La Hoya, Torrevieja, situé dans l?un des quartiers les plus recherchés de la Costa Blanca Sud. La résidence propose des appartements contemporains de 2 et 3 chambres, avec 2 salles de bains, dont une en-suite, ainsi qu?une buanderie indépendante, conçus pour offrir confort, luminosité et fonctionnalité. Parking souterrain et débarras inclus. Cette promotion se compose de bâtiments de faible hauteur entourés de vastes espaces communs paysagers et propose : - Piscines communes pour adultes et enfants - Jardins méditerranéens - Aire de jeux pour enfants - Salle de sport intérieure et extérieure - Terrains de padel - Parking à vélos - Spa avec sauna Le projet propose plusieurs configurations: - Appartements en rez-de-chaussée avec jardin privé - Appartements avec grandes terrasses - Penthouses avec solarium privé sur le toit Chaque logement permet de profiter pleinement du climat méditerranéen et d?un cadre de vie agréable toute l?année. Situé entre les lacs salés de La Mata et Torrevieja, le quartier résidentiel de La Hoya offre un environnement calme tout en restant proche de toutes les commodités : - Supermarchés, restaurants et centres médicaux - Pistes cyclables et zones vertes - Accès rapide aux plages de Torrevieja (3,5 km) - Proximité du parc naturel de La Mata - Le centre-ville de Torrevieja, ses centres commerciaux, hôpitaux, cinémas, théâtres et le parc aquatique Aquopolis sont accessibles en quelques minutes en voiture. Prix: Rez: àpd 310.000 ? hors frais Étages intermédiaires: àpd 280.000 ? hors frais Penthouses: àpd 325.000 ? hors frais Livraison: juillet 2027', 'Ontdek dit nieuwe residentiële project met nieuwbouwappartementen in La Hoya, Torrevieja, gelegen in een van de meest gewilde wijken van de Costa Blanca Zuid. De residentie biedt moderne appartementen met 2 en 3 slaapkamers, 2 badkamers, waarvan één en suite, evenals een aparte wasruimte, ontworpen voor optimaal comfort, lichtinval en functionaliteit. Ondergrondse parkeerplaats en berging inbegrepen. Dit project bestaat uit laagbouwgebouwen omgeven door ruime, aangelegde gemeenschappelijke zones en biedt onder andere: * Gemeenschappelijke zwembaden voor volwassenen en kinderen * Mediterrane tuinen * Speeltuin voor kinderen * Binnen- en buitengym * Padelbanen * Fietsenstalling * Spa met sauna Het project biedt verschillende woningtypes: * Gelijkvloerse appartementen met privé tuin * Appartementen met ruime terrassen * Penthouses met privé solarium op het dak Elke woning laat u het hele jaar door genieten van het mediterrane klimaat en een aangename leefomgeving. Gelegen tussen de zoutmeren van La Mata en Torrevieja, biedt de residentiële wijk La Hoya een rustige omgeving met alle voorzieningen binnen handbereik: * Supermarkten, restaurants en medische centra * Fietspaden en groenzones * Snelle toegang tot de stranden van Torrevieja (3,5 km) * Dicht bij het natuurpark van La Mata * Het centrum van Torrevieja met winkelcentra, ziekenhuizen, bioscopen, theaters en het waterpark Aquopolis is in enkele minuten met de auto bereikbaar Prijzen: * Gelijkvloers: vanaf ?310.000 exclusief kosten * Tussenverdiepingen: vanaf ?280.000 exclusief kosten * Penthouses: vanaf ?325.000 exclusief kosten Oplevering: juli 2027', '', 280000, 'torrevieja-superbes-appartements-modernes-en-2-chambres', 'torrevieja-prachtige-moderne-appartementen-met-2-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2004', 'Torrevieja: superbes appartements modernes en 3 chambres', 'Torrevieja: prachtige moderne appartementen met 3 slaapkamers', '', 'Découvrez ce nouveau complexe résidentiel d?appartements neufs à La Hoya, Torrevieja, situé dans l?un des quartiers les plus recherchés de la Costa Blanca Sud. La résidence propose des appartements contemporains de 2 et 3 chambres, avec 2 salles de bains, dont une en-suite, ainsi qu?une buanderie indépendante, conçus pour offrir confort, luminosité et fonctionnalité. Parking souterrain et débarras inclus. Cette promotion se compose de bâtiments de faible hauteur entourés de vastes espaces communs paysagers et propose : - Piscines communes pour adultes et enfants - Jardins méditerranéens - Aire de jeux pour enfants - Salle de sport intérieure et extérieure - Terrains de padel - Parking à vélos - Spa avec sauna Le projet propose plusieurs configurations: - Appartements en rez-de-chaussée avec jardin privé - Appartements avec grandes terrasses - Penthouses avec solarium privé sur le toit Chaque logement permet de profiter pleinement du climat méditerranéen et d?un cadre de vie agréable toute l?année. Situé entre les lacs salés de La Mata et Torrevieja, le quartier résidentiel de La Hoya offre un environnement calme tout en restant proche de toutes les commodités : - Supermarchés, restaurants et centres médicaux - Pistes cyclables et zones vertes - Accès rapide aux plages de Torrevieja (3,5 km) - Proximité du parc naturel de La Mata - Le centre-ville de Torrevieja, ses centres commerciaux, hôpitaux, cinémas, théâtres et le parc aquatique Aquopolis sont accessibles en quelques minutes en voiture. Prix: Rez: àpd 375.000 ? hors frais Étages intermédiaires: àpd 345.000 ? hors frais Penthouses: àpd 395.000 ? hors frais Livraison: juillet 2027', 'Ontdek dit nieuwe residentiële project met nieuwbouwappartementen in La Hoya, Torrevieja, gelegen in een van de meest gewilde wijken van de Costa Blanca Zuid. De residentie biedt moderne appartementen met 2 en 3 slaapkamers, 2 badkamers, waarvan één en suite, evenals een aparte wasruimte, ontworpen voor optimaal comfort, lichtinval en functionaliteit. Ondergrondse parkeerplaats en berging inbegrepen. Dit project bestaat uit laagbouwgebouwen omgeven door ruime, aangelegde gemeenschappelijke zones en biedt onder andere: * Gemeenschappelijke zwembaden voor volwassenen en kinderen * Mediterrane tuinen * Speeltuin voor kinderen * Binnen- en buitengym * Padelbanen * Fietsenstalling * Spa met sauna Het project biedt verschillende woningtypes: * Gelijkvloerse appartementen met privé tuin * Appartementen met ruime terrassen * Penthouses met privé solarium op het dak Elke woning laat u het hele jaar door genieten van het mediterrane klimaat en een aangename leefomgeving. Gelegen tussen de zoutmeren van La Mata en Torrevieja, biedt de residentiële wijk La Hoya een rustige omgeving met alle voorzieningen binnen handbereik: * Supermarkten, restaurants en medische centra * Fietspaden en groenzones * Snelle toegang tot de stranden van Torrevieja (3,5 km) * Dicht bij het natuurpark van La Mata * Het centrum van Torrevieja met winkelcentra, ziekenhuizen, bioscopen, theaters en het waterpark Aquopolis is in enkele minuten met de auto bereikbaar Prijzen: * Gelijkvloers: vanaf ?375.000 exclusief kosten * Tussenverdiepingen: vanaf ?345.000 exclusief kosten * Penthouses: vanaf ?395.000 exclusief kosten Oplevering: juli 2027', '', 345000, 'torrevieja-superbes-appartements-modernes-en-3-chambres', 'torrevieja-prachtige-moderne-appartementen-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2006', 'Avileses : belles maisons 3 chambres de plain-pied', '', '', 'Ces 5 maisons de plain-pied, avec piscine privée, sont situées à Avileses près de plusieurs terrains de golf tels que La Torre Golf et Hacienda Riquelme, à 20 minutes en voiture de l''aéroport de Murcia et à 15 minutes de la Mar Menor et des plages méditerranéennes. Elles sont entourées de tous les services et installations sportives, Les maisons offrent 3 chambres, 2 salles de bains, une cuisine équipée ouverte donnant sur le living avec portes-fenêtres vers la terrasse avec piscine privée. Vaste solarium au 1er étage. Sont inclus dans le prix: la piscine et les électroménagers. Prix: de 279.900 ?à 299.9000 ? hors frais Fin des travaux: juin 2027', '', '', 279900, 'avileses-belles-maisons-3-chambres-de-plain-pied', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2011', 'Torre Pacheco : beaux appartements 3 chambres', '', '', 'Découvrez cette nouvelle résidence située à Torre Pacheco, composée de 24 appartements de 2 ou 3 chambres, pensés pour offrir confort, élégance et qualité de vie. Les logements du rez-de-chaussée disposent de généreuses terrasses, tandis que ceux à l?étage bénéficient de terrasses privées et d''un solarium. Chaque solarium est équipé d?une pergola, d?un espace barbecue et d?une structure renforcée permettant l?installation d?un jacuzzi, idéal pour profiter pleinement du climat méditerranéen. Tous les biens comprennent une place de stationnement ainsi qu?un système de climatisation complet, garantissant un confort optimal en toute saison. La résidence bénéficie d?un emplacement privilégié, au c?ur de Torre Pacheco, à proximité immédiate de toutes les commodités du quotidien : supermarchés, commerces, bars et restaurants. Le centre-ville, animé et authentique, se rejoint facilement à pied. Les amateurs de mer apprécieront la proximité de la Mar Menor, accessible en une dizaine de minutes en voiture, réputée pour ses plages de sable fin et ses eaux calmes. La résidence offre également de très beaux espaces communs, avec des jardins paysagers soignés et une piscine invitant à la détente. Torre Pacheco est particulièrement appréciée des amateurs de golf, grâce à la présence de plusieurs parcours renommés situés à quelques minutes seulement. Cette localisation stratégique permet aussi de rejoindre facilement les principaux points d?intérêt de la région :plusieurs centres commerciaux à moins de 15 km, et les plages de la Costa Cálida à une courte distance en voiture. Les ports et marinas voisins complètent une offre de loisirs variée, entre navigation de plaisance et sports nautiques. Prix: Rez-de-chaussée 3 chambres : 1 unité à 230.000 ? hors frais 1er étage 3 chambres : 240.000 ? hors frais Livraison: début 2027', '', '', 230000, 'torre-pacheco-beaux-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2012', 'La Manga : appartements 1 chambre dans un cadre unique !', '', '', 'Un emplacement rare au c?ur d?un environnement naturel exceptionnel ! Ce nouveau complexe résidentiel bénéficie d?une situation tout simplement unique : entre la Mar Menor et la Mer Méditerranée. Vous profitez ici d?un cadre privilégié, entouré de plages de sable fin aux eaux calmes et cristallines. Tous les services essentiels sont accessibles à proximité immédiate : commerces, restaurants, infrastructures médicales et installations de loisirs, pour un quotidien confortable et sans contraintes, aussi bien en résidence principale qu?en résidence secondaire. Les appartements ont été soigneusement conçus afin de tirer le meilleur parti de chaque mètre carré, tout en s?intégrant harmonieusement à leur environnement naturel. Le choix des matériaux, la qualité des finitions et la conception intelligente des espaces garantissent confort, fonctionnalité et esthétisme. À l?extérieur, les résidents peuvent profiter d?une piscine commune, idéale pour se détendre sous le soleil. La Manga est une étroite bande de terre naturelle entourée de deux mers, offrant un microclimat exceptionnel. Cette singularité, associée à une large offre de loisirs ? sports nautiques, golf, restaurants, commerces ? en fait l?une des destinations les plus exotiques d''Espagne. Prix: 1 chambre à partir de 205.033 ? hors frais Inclus: - Climatisation - Électroménagers (four, plaque vitrocéramique, hotte, frigo et lave-vaisselle) Place de parking en supplément.', '', '', 205033, 'la-manga-appartements-1-chambre-dans-un-cadre-unique', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-2013', 'La Manga : appartements 2 chambres dans un cadre unique !', '', '', 'Un emplacement rare au c?ur d?un environnement naturel exceptionnel ! Ce nouveau complexe résidentiel bénéficie d?une situation tout simplement unique : entre la Mar Menor et la Mer Méditerranée. Vous profitez ici d?un cadre privilégié, entouré de plages de sable fin aux eaux calmes et cristallines. Tous les services essentiels sont accessibles à proximité immédiate : commerces, restaurants, infrastructures médicales et installations de loisirs, pour un quotidien confortable et sans contraintes, aussi bien en résidence principale qu?en résidence secondaire. Les appartements ont été soigneusement conçus afin de tirer le meilleur parti de chaque mètre carré, tout en s?intégrant harmonieusement à leur environnement naturel. Le choix des matériaux, la qualité des finitions et la conception intelligente des espaces garantissent confort, fonctionnalité et esthétisme. À l?extérieur, les résidents peuvent profiter d?une piscine commune, idéale pour se détendre sous le soleil. La Manga est une étroite bande de terre naturelle entourée de deux mers, offrant un microclimat exceptionnel. Cette singularité, associée à une large offre de loisirs ? sports nautiques, golf, restaurants, commerces ? en fait l?une des destinations les plus exotiques d''Espagne. Prix: 2 chambres à partir de 237.132 ? hors frais Inclus: - Climatisation - Électroménagers (four, plaque vitrocéramique, hotte, frigo et lave-vaisselle) Place de parking en supplément.', '', '', 237132, 'la-manga-appartements-2-chambres-dans-un-cadre-unique', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
